const { exec } = require('child_process');
const { promisify } = require('util');
const execAsync = promisify(exec);

module.exports = async function (context, req) {
    const inputFile = req.body.inputFile;
    const outputFormat = req.body.outputFormat;

    if (!inputFile || !outputFormat) {
        context.res = {
            status: 400,
            body: "Please provide both inputFile and outputFormat in the request body."
        };
        return;
    }

    // Validate and sanitize input
    const allowedFormats = ['pdf', 'docx', 'txt', 'odt'];
    const sanitizedInputFile = inputFile.replace(/[^a-zA-Z0-9._-]/g, '');
    const sanitizedOutputFormat = allowedFormats.includes(outputFormat) ? outputFormat : null;

    if (!sanitizedOutputFormat) {
        context.res = {
            status: 400,
            body: "Invalid output format specified."
        };
        return;
    }

    try {
        const command = `libreoffice --headless --convert-to ${sanitizedOutputFormat} ${sanitizedInputFile}`;
        await execAsync(command);

        context.res = {
            status: 200,
            body: `File converted successfully to ${sanitizedOutputFormat}.`
        };
    } catch (error) {
        context.res = {
            status: 500,
            body: `Error converting file: ${error.message}`
        };
    }
};